1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_SIZE = 3;
3	const BLOCK_OF_THREE_PREMIUM = 60;
4	const CURSED_SURCHARGE = 0.5;
5	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	const FIRST_INSURANCE_SURCHARGE = 0.1;
8	const LOYALTY_DISCOUNT = -0.2;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	const FOLLOW_UP_DISCOUNT = -0.15;
11	
12	const BASE_PREMIUM: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
24	type Customer = { yearsWithMHPCO?: number; firstInsurance?: boolean };
25	type Step = { op: "quote"; items: Item[] };
26	type Scenario = { customer: Customer; steps: Step[] };
27	
28	const basePremiumFor = (type: string): number => {
29	  const premium = BASE_PREMIUM[type];
30	  if (premium === undefined) throw new Error(`unknown item type: ${type}`);
31	  return premium;
32	};
33	
34	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
35	
36	const isMainItem = (item: Item): boolean => !isComponent(item);
37	
38	const groupByType = (items: Item[]): Map<string, number> =>
39	  items.reduce((counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1), new Map<string, number>());
40	
41	const componentGroupPremium = (type: string, count: number): number =>
42	  count === BLOCK_OF_THREE_SIZE ? BLOCK_OF_THREE_PREMIUM : count * basePremiumFor(type);
43	
44	const componentsPremium = (items: Item[]): number =>
45	  Array.from(groupByType(items.filter(isComponent)))
46	    .reduce((sum, [type, count]) => sum + componentGroupPremium(type, count), 0);
47	
48	const isHighlyEnchanted = (item: Item): boolean =>
49	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
50	
51	const rateWhen = (applies: boolean, rate: number): number => (applies ? rate : 0);
52	
53	const applyRate = (base: number, rate: number): number => base * (1 + rate);
54	
55	const itemRateAdjustment = (item: Item): number =>
56	  rateWhen(item.cursed === true, CURSED_SURCHARGE) +
57	  rateWhen(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE);
58	
59	const itemPremium = (item: Item): number =>
60	  applyRate(basePremiumFor(item.type), itemRateAdjustment(item));
61	
62	type PremiumBreakdown = { base: number; withSurcharges: number };
63	
64	const addBreakdowns = (a: PremiumBreakdown, b: PremiumBreakdown): PremiumBreakdown => ({
65	  base: a.base + b.base,
66	  withSurcharges: a.withSurcharges + b.withSurcharges,
67	});
68	
69	const mainItemBreakdown = (item: Item): PremiumBreakdown => ({
70	  base: basePremiumFor(item.type),
71	  withSurcharges: itemPremium(item),
72	});
73	
74	const componentsBreakdown = (items: Item[]): PremiumBreakdown => {
75	  const total = componentsPremium(items);
76	  return { base: total, withSurcharges: total };
77	};
78	
79	const itemsBreakdown = (items: Item[]): PremiumBreakdown =>
80	  items
81	    .filter(isMainItem)
82	    .map(mainItemBreakdown)
83	    .reduce(addBreakdowns, componentsBreakdown(items));
84	
85	const isLongStanding = (customer: Customer): boolean =>
86	  (customer.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD;
87	
88	const policyRateAdjustment = (customer: Customer, isFollowUp: boolean): number =>
89	  rateWhen(customer.firstInsurance === true, FIRST_INSURANCE_SURCHARGE) +
90	  rateWhen(isLongStanding(customer), LOYALTY_DISCOUNT) +
91	  rateWhen(isFollowUp, FOLLOW_UP_DISCOUNT);
92	
93	const FLOATING_POINT_EPSILON = 1e-9;
94	
95	const roundUpInOurFavor = (amount: number): number =>
96	  Math.ceil(amount - FLOATING_POINT_EPSILON);
97	
98	const policyPremium = (customer: Customer, items: Item[], isFollowUp: boolean): number => {
99	  const { base, withSurcharges } = itemsBreakdown(items);
100	  return withSurcharges + base * policyRateAdjustment(customer, isFollowUp) + PROCESSING_FEE;
101	};
102	
103	const isFollowUpStep = (stepIndex: number): boolean => stepIndex > 0;
104	
105	const quote = (customer: Customer) => ({ items }: Step, stepIndex: number): { premium: number } => ({
106	  premium: roundUpInOurFavor(policyPremium(customer, items, isFollowUpStep(stepIndex))),
107	});
108	
109	export const runScenario = (input: unknown): unknown => {
110	  const { customer, steps } = input as Scenario;
111	  return { results: steps.map(quote(customer)) };
112	};
